-- a4d00000-0000-4000-8000-000000000000 動画別3問クイズ + 既存コース末(a4d90000-0000-4000-8000-000000000000)を末尾へ  自動生成
UPDATE public.lessons SET sort_order=1 WHERE id='a4d01000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=3 WHERE id='a4d02000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=5 WHERE id='a4d03000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=7 WHERE id='a4d04000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=9 WHERE id='a4d05000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=99 WHERE id='a4d90000-0000-4000-8000-000000000000';

ON CONFLICT (id) DO UPDATE SET course_id=EXCLUDED.course_id,title=EXCLUDED.title,content_type=EXCLUDED.content_type,estimated_minutes=EXCLUDED.estimated_minutes,sort_order=EXCLUDED.sort_order;

